  /**
   * Comprehensive query validation pipeline.
   * Returns either a validated/sanitized query or a list of validation errors.
   */
  def validateQuery(rawQuery: String): QueryValidationResult = {
    val errors = scala.collection.mutable.ListBuffer[ValidationError]()

    // 1. Null/empty check
    if (rawQuery == null || rawQuery.trim.isEmpty) {
      return QueryValidationResult(isValid = false, errors = Seq(EmptyQuery()), sanitizedQuery = None)
    }

    val trimmedQuery = rawQuery.trim

    // 2. Length check
    if (trimmedQuery.length > maxQueryLength) {
      errors += QueryTooLong(trimmedQuery.length, maxQueryLength)
      return QueryValidationResult(isValid = false, errors = errors.toSeq, sanitizedQuery = None)
    }

    // 3. Remove trailing semicolons (single statement only)
    val queryNoTrailingSemicolon = trimmedQuery.replaceAll(";\\s*$", "").trim

    // 4. Check for multiple statements
    if (queryNoTrailingSemicolon.contains(";")) {
      errors += MultipleStatements()
    }

    // 5. Must start with SELECT or WITH (CTE)
    val upperQuery = queryNoTrailingSemicolon.toUpperCase.replaceAll("\\s+", " ").trim
    if (!upperQuery.startsWith("SELECT ") && !upperQuery.startsWith("SELECT\n") &&
        !upperQuery.startsWith("WITH ") && !upperQuery.startsWith("WITH\n") &&
        !upperQuery.startsWith("(SELECT ")) {
      errors += NotASelectQuery()
    }

    // 6. Check for forbidden statements
    val tokens = upperQuery.split("\\s+|\\(|\\)|,").map(_.trim).filter(_.nonEmpty).toSet
    for (forbidden <- forbiddenStatements) {
      // Check if the forbidden keyword appears as a standalone token
      // (not as part of a column name or alias)
      if (tokens.contains(forbidden) && forbidden != "SELECT") {
        // Allow these only in specific safe contexts
        val isSafeUsage = forbidden match {
          case "DESCRIBE" | "SHOW" | "EXPLAIN" | "ANALYZE" => false
          case _ => false
        }
        if (!isSafeUsage) {
          // More precise check: look for the keyword as a standalone word
          val pattern = s"(?i)\\b${Regex.quote(forbidden)}\\b".r
          if (pattern.findFirstIn(queryNoTrailingSemicolon).isDefined) {
            errors += ForbiddenStatement(forbidden)
          }
        }
      }
    }

    // 7. Check for forbidden patterns
    for (pattern <- forbiddenPatterns) {
      if (pattern.findFirstIn(queryNoTrailingSemicolon).isDefined) {
        errors += ForbiddenPattern(pattern.toString)
      }
    }

    // 8. Validate referenced tables against allowlist
    val referencedTables = extractTableReferences(queryNoTrailingSemicolon)
    for (table <- referencedTables) {
      val normalizedTable = table.toLowerCase.replaceAll("`", "").replaceAll("\"", "")
      if (!allowedTables.contains(normalizedTable)) {
        errors += UnauthorizedTable(table)
      }
    }

    if (errors.nonEmpty) {
      QueryValidationResult(isValid = false, errors = errors.toSeq, sanitizedQuery = None)
    } else {
      QueryValidationResult(isValid = true, errors = Seq.empty, sanitizedQuery = Some(queryNoTrailingSemicolon))
    }
  }

  /**
   * Extract table references from a SQL query.
   * This uses a conservative regex-based approach to find FROM and JOIN clauses.
   * For production, consider using Spark's LogicalPlan parser for AST-based extraction.
   */
  def extractTableReferences(query: String): Set[String] = {
    val tables = scala.collection.mutable.Set[String]()

    // Pattern to match table references after FROM and JOIN keywords
    // Handles: schema.table, `schema`.`table`, "schema"."table"
    val tableRefPattern = """(?i)(?:FROM|JOIN)\s+([\w`"]+\.[\w`"]+|[\w`"]+)""".r

    for (m <- tableRefPattern.findAllMatchIn(query)) {
      val tableRef = m.group(1).replaceAll("`", "").replaceAll("\"", "")
      tables += tableRef
    }

    tables.toSet
  }

