  /**
   * Execute a parameterized query template safely.
   * Parameters are validated against their definitions and bound safely.
   */
  def executeTemplateQuery(
    spark: SparkSession,
    templateId: String,
    parameters: Map[String, String],
    userId: String,
    requestId: String
  ): QueryResult = {

    val queryId = java.util.UUID.randomUUID().toString

    // Validate template exists
    val template = queryTemplates.get(templateId) match {
      case Some(t) => t
      case None =>
        return QueryResult(
          success = false, data = None, schema = None, rowCount = None,
          errorMessage = Some(s"Unknown query template: $templateId"),
          queryId = queryId
        )
    }

    // Validate all required parameters are present
    val missingParams = template.parameters.filter(_.required).filterNot(p => parameters.contains(p.name))
    if (missingParams.nonEmpty) {
      return QueryResult(
        success = false, data = None, schema = None, rowCount = None,
        errorMessage = Some(s"Missing required parameters: ${missingParams.map(_.name).mkString(", ")}"),
        queryId = queryId
      )
    }

    // Validate and sanitize each parameter
    val sanitizedParams = scala.collection.mutable.ListBuffer[String]()
    for (paramDef <- template.parameters) {
      val rawValue = parameters.getOrElse(paramDef.name, "")

      val validationResult = paramDef.paramType match {
        case DateParam =>
          validateDateParam(rawValue)
        case IntParam =>
          validateIntParam(rawValue)
        case StringEnumParam =>
          validateEnumParam(rawValue, paramDef.allowedValues.getOrElse(Set.empty))
      }

      validationResult match {
        case Right(sanitized) => sanitizedParams += sanitized
        case Left(error) =>
          return QueryResult(
            success = false, data = None, schema = None, rowCount = None,
            errorMessage = Some(s"Invalid parameter '${paramDef.name}': $error"),
            queryId = queryId
          )
      }
    }

    // Build the query by replacing ? placeholders with validated, properly quoted values
    var finalQuery = template.sqlTemplate
    for ((paramDef, sanitizedValue) <- template.parameters.zip(sanitizedParams)) {
      val quotedValue = paramDef.paramType match {
        case DateParam => s"'$sanitizedValue'"
        case IntParam => sanitizedValue // No quoting for integers
        case StringEnumParam => s"'$sanitizedValue'"
      }
      // Replace the first occurrence of ?
      finalQuery = finalQuery.replaceFirst("\\?", java.util.regex.Matcher.quoteReplacement(quotedValue))
    }

    logAuditEvent(userId, requestId, queryId, finalQuery, "TEMPLATE_EXEC", s"Template: $templateId")

    // Execute the constructed query
    Try {
      val df = spark.sql(finalQuery)
      val rows = df.limit(maxResultRows).collect()
      (rows, df.schema, rows.length.toLong)
    } match {
      case Success((rows, schema, count)) =>
        logAuditEvent(userId, requestId, queryId, finalQuery, "SUCCESS", s"Returned $count rows")
        QueryResult(
          success = true, data = Some(rows), schema = Some(schema),
          rowCount = Some(count), errorMessage = None, queryId = queryId
        )
      case Failure(ex) =>
        logAuditEvent(userId, requestId, queryId, finalQuery, "ERROR", ex.getMessage)
        QueryResult(
          success = false, data = None, schema = None, rowCount = None,
          errorMessage = Some(s"Query execution error: ${ex.getMessage}"),
          queryId = queryId
        )
    }
  }

  // ---------------------------------------------------------------------------
  // Parameter Validation Helpers
