  private val datePattern = """^\d{4}-\d{2}-\d{2}$""".r

  def validateDateParam(value: String): Either[String, String] = {
    if (datePattern.findFirstIn(value).isEmpty) {
      Left("Date must be in YYYY-MM-DD format")
    } else {
      Try(java.time.LocalDate.parse(value)) match {
        case Success(date) =>
          // Ensure date is within reasonable range
          val now = java.time.LocalDate.now()
          if (date.isBefore(now.minusYears(10)) || date.isAfter(now.plusDays(1))) {
            Left("Date must be within the last 10 years and not in the future")
          } else {
            Right(date.toString)
          }
        case Failure(_) => Left("Invalid date value")
      }
    }
  }

  def validateIntParam(value: String): Either[String, String] = {
    Try(value.toLong) match {
      case Success(n) if n >= 0 && n <= Int.MaxValue => Right(n.toString)
      case Success(_) => Left("Integer out of allowed range")
      case Failure(_) => Left("Value must be a valid integer")
    }
  }

  def validateEnumParam(value: String, allowedValues: Set[String]): Either[String, String] = {
    val normalized = value.trim
    if (allowedValues.contains(normalized)) {
      Right(normalized)
    } else {
      Left(s"Value must be one of: ${allowedValues.mkString(", ")}")
    }
  }

