  def logAuditEvent(
    userId: String,
    requestId: String,
    queryId: String,
    query: String,
    status: String,
    details: String
  ): Unit = {
    // In production, write to a secure audit log (e.g., append-only table, SIEM)
    val timestamp = java.time.Instant.now().toString
    val sanitizedUserId = userId.replaceAll("[^a-zA-Z0-9_-]", "")
    val truncatedQuery = if (query.length > 500) query.take(500) + "..." else query

    println(
      s"""[AUDIT] timestamp=$timestamp | userId=$sanitizedUserId | requestId=$requestId | """ +
      s"""queryId=$queryId | status=$status | details=$details | query=$truncatedQuery"""
    )
  }

