  def createSecureSparkSession(): SparkSession = {
    SparkSession.builder()
      .appName("SecureSqlAnalyticsPlatform")
      .config("spark.sql.crossJoin.enabled", "false")
      // Limit broadcast join threshold to prevent memory abuse
      .config("spark.sql.autoBroadcastJoinThreshold", "10485760") // 10MB
      // Set query timeout
      .config("spark.network.timeout", "300s")
      // Disable dynamic resource allocation abuse
      .config("spark.dynamicAllocation.maxExecutors", "20")
      // Restrict file access
      .config("spark.sql.warehouse.dir", "/secure/warehouse")
      .getOrCreate()
  }

